#include<bits/stdc++.h>
using namespace std;
bool flag;
bool judgement(int a){
    if((a%4==0&&a%100!=0)||a%400==0){
        return true;
    }
    else{
        return false;
    }
}
int main(){
    int a,b;
    scanf("%d",&a);
    scanf("%d",&b);
    int i,sum=0,t;
    for(int i=a/10000;i<=b/10000;i++){
        if((i%100==10||i%100==30||i%100==50||i%100==70||i%100==80||i%100==1||i%100==21)&&(i/1000+i/100%10*10>=1||i/1000+i/100%10*10<=31)){
            if(i*10000+i%10*1000+i/10%10*100+i/100%10*10+i/1000>=a&&i*10000+i%10*1000+i/10%10*100+i/100%10*10+i/1000<=b){
                sum++;
            }
        }
        else if((i%100==40||i%100==60||i%100==90||i%100==11)&&(i/1000+i/100%10*10>=1||i/1000+i/100%10*10<=30)){
            if(i*10000+i%10*1000+i/10%10*100+i/100%10*10+i/1000>=a&&i*10000+i%10*1000+i/10%10*100+i/100%10*10+i/1000<=b){
                sum++;
            }
        }
        else{
            t=i;
            flag=judgement(t);
            if(flag){
                 if(i/1000+i/100%10*10>=1||i/1000+i/100%10*10<=28){
                     if(i*10000+i%10*1000+i/10%10*100+i/100%10*10+i/1000>=a&&i*10000+i%10*1000+i/10%10*100+i/100%10*10+i/1000<=b){
                            sum++;
                 }
            }
        }
        else{
            if(i/1000+i/100%10*10>=1||i/1000+i/100%10*10<=29){
                     if(i*10000+i%10*1000+i/10%10*100+i/100%10*10+i/1000>=a&&i*10000+i%10*1000+i/10%10*100+i/100%10*10+i/1000<=b){
                            sum++;
                 }
            }
        }
    }
}
cout<<sum<<endl;
return 0;
}